9	// InferTier returns a recommended ModelTier for a bead based on its metadata.
10	// It inspects, in priority order: an explicit "tier:" label, the kind/priority
11	// labels and IssueType, then falls back to an estimated-scope heuristic on the
12	// description length.
13	//
14	// The default for a bead with no useful signal is TierCheap, matching the
15	// hot-fix behavior in cmd/agent_cmd.go runAgentExecuteLoopImpl that this
16	// engine replaces. Aligns with the endpoint-first routing redesign goal of
17	// cheap-by-default with metadata-driven escalation.
18	func InferTier(b *bead.Bead) ModelTier {
19		if b == nil {
20			return TierCheap
21		}
22	
23		kindLabel := ""
24		priorityLabel := ""
25		for _, raw := range b.Labels {
26			l := strings.ToLower(strings.TrimSpace(raw))
27			if l == "" {
28				continue
29			}
30			// Explicit override wins.
31			if v, ok := strings.CutPrefix(l, "tier:"); ok {
32				switch strings.TrimSpace(v) {
33				case "smart":
34					return TierSmart
35				case "standard":
36					return TierStandard
37				case "cheap":
38					return TierCheap
39				}
40			}
41			if v, ok := strings.CutPrefix(l, "kind:"); ok {
42				kindLabel = strings.TrimSpace(v)
43			}
44			if v, ok := strings.CutPrefix(l, "priority:"); ok {
45				priorityLabel = strings.TrimSpace(v)
46			}
47		}
48	
49		// Priority drives the floor: critical/high work gets smart, low/trivial
50		// is happy at cheap. Medium falls through to kind- and scope-based logic.
51		switch priorityLabel {
52		case "critical", "urgent":
53			return TierSmart
54		case "high":
55			// High priority bugs/incidents go to smart; high enhancements stay
56			// at standard so we don't burn smart-tier budget on routine work.
57			if isBugKind(kindLabel) || isBugKind(b.IssueType) {
58				return TierSmart
59			}
60			return TierStandard
61		case "low", "trivial":
62			return TierCheap
63		}
64	
65		kind := kindLabel
66		if kind == "" {
67			kind = strings.ToLower(strings.TrimSpace(b.IssueType))
68		}
69		switch {
70		case isBugKind(kind):
71			return TierStandard
72		case isCheapKind(kind):
73			return TierCheap
74		case isStandardKind(kind):
75			return TierStandard
76		}
77	
78		// Estimated scope from description length. Long, dense descriptions tend
79		// to indicate larger work; short descriptions are typically mechanical.
80		descLen := len(b.Description) + len(b.Acceptance)
81		switch {
82		case descLen >= 4000:
83			return TierSmart
84		case descLen >= 1500:
85			return TierStandard
86		default:
87			return TierCheap
88		}
89	}
